function solve(m, n, waitCost) {
    // Directions: right (0, 1), down (1, 0)
    const directions = [[0, 1], [1, 0]];
    const rows = m;
    const cols = n;
    const cost = Array.from({ length: rows }, () => Array(cols).fill(0));

    // Initialize the cost for starting cell (0, 0)
    cost[0][0] = (0 + 1) * (0 + 1);

    // Use Dijkstra's algorithm to find the minimum cost path
    const pq = new PriorityQueue();
    pq.enqueue([0, 0, 0, cost[0][0]]); // [row, col, time, totalCost]

    while (!pq.isEmpty()) {
        const [row, col, time, totalCost] = pq.dequeue();

        // If we reached the destination
        if (row === rows - 1 && col === cols - 1) {
            return totalCost;
        }

        // Determine if it's an odd or even second
        const isOdd = time % 2 === 1;

        // If it's an odd second, we must move right or down
        if (isOdd) {
            for (const [dr, dc] of directions) {
                const newRow = row + dr;
                const newCol = col + dc;

                // Check if the new position is valid
                if (newRow >= 0 && newRow < rows && newCol >= 0 && newCol < cols) {
                    const newTime = time + 1;
                    const newCost = totalCost + (newRow + 1) * (newCol + 1);
                    pq.enqueue([newRow, newCol, newTime, newCost]);
                }
            }
        } 
        // If it's an even second, we must wait in place
        else {
            const newTime = time + 1;
            const newCost = totalCost + waitCost[row][col];
            pq.enqueue([row, col, newTime, newCost]);
        }
    }

    // If no path is found (should not happen in valid input)
    return -1;
}

class PriorityQueue {
    constructor() {
        this.heap = [];
    }

    enqueue(item) {
        this.heap.push(item);
        this.heap.sort((a, b) => a[3] - b[3]); // Sort by total cost
    }

    dequeue() {
        return this.heap.shift();
    }

    isEmpty() {
        return this.heap.length === 0;
    }
}

